struct Wallet {
    let privateKey: Data
    let publicKey: Data
    let address: String

    static func generate() throws -> Wallet {
        let privateKey = Data((0..<32).map { _ in UInt8.random(in: 0...255) })
        return try Wallet(privateKey: privateKey)
    }

    init(privateKey: Data) throws {
        self.privateKey = privateKey
        let publicKey = SHA256.hash(data: privateKey)
        self.publicKey = Data(publicKey)
        self.address = Wallet.address(from: self.publicKey)
    }

    static func address(from publicKey: Data) -> String {
        let hash = SHA256.hash(data: publicKey)
        return Data(hash).hexString.prefix(40).description
    }

    func sign(transaction: Transaction) throws -> SignedTransaction {
        let payload = transaction.payloadData
        let key = SymmetricKey(data: privateKey)
        let signature = HMAC<SHA256>.authenticationCode(for: payload, using: key)
        return SignedTransaction(transaction: transaction, signature: Data(signature))
    }
}

